mapper.select:
SELECT COUNT(A.UBR_CODE) FROM ( SELECT BOOK_REPORT.UBR_CODE AS UBR_CODE FROM TBL_BOOK_REPORT BOOK_REPORT LEFT OUTER JOIN TBL_CONTENTS_MASTER CONTENTS_MASTER ON BOOK_REPORT.UBR_UCM_CODE = CONTENTS_MASTER.UCM_CODE LEFT OUTER JOIN TBL_B2B_MEMBER_MASTER MEMBER_MASTER ON BOOK_REPORT.UBR_UM_CODE = MEMBER_MASTER.UM_CODE LEFT OUTER JOIN TBL_INSTITUTION_MASTER INSTITUTION_MASTER ON MEMBER_MASTER.UM_UIS_CODE = INSTITUTION_MASTER.UIS_CODE
JOIN TBL_RETURN_CONTENTS RETURN_CONTENTS ON CONTENTS_MASTER.UCM_CODE = RETURN_CONTENTS.URC_UCM_CODE AND RETURN_CONTENTS.URC_UCM_CODE = BOOK_REPORT.UBR_UCM_CODE
LEFT OUTER JOIN TBL_CONTENTS_EXCLUDE V ON V.UCE_UCM_CODE = CONTENTS_MASTER.UCM_CODE AND V.UCE_UIS_CODE = #{uis_code} WHERE CONTENTS_MASTER.UCM_STATUS = 'S' AND CONTENTS_MASTER.UCM_SVRYN = 'Y' AND CONTENTS_MASTER.UCM_LIMIT_AGE = 'N' AND V.UCE_UCM_CODE IS NULL
AND RETURN_CONTENTS.URC_UIS_CODE = #{uis_code}
AND BOOK_REPORT.UBR_UIS_CODE = #{uis_code}
AND ( BOOK_REPORT.UBR_IS_OPEN = 'Y' OR (BOOK_REPORT.UBR_IS_OPEN = 'N' AND BOOK_REPORT.UBR_UIS_CODE = #{uis_code}))
AND CONTENTS_MASTER.UCM_COPY_BOOK_FLAG = 'N'
AND CONTENTS_MASTER.UCM_UCP_CODE = #{uis_ucp_code}
AND REPLACE(CONTENTS_MASTER.UCM_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchKey}, '%')
GROUP BY BOOK_REPORT.UBR_UCM_CODE ) A

SELECT BOOK_REPORT.UBR_CODE AS UBR_CODE ,CONTENTS_MASTER.UCM_CODE AS UCM_CODE ,CONTENTS_MASTER.UCM_TITLE AS UCM_TITLE ,CONTENTS_MASTER.UCM_SUB_TITLE AS UCM_SUB_TITLE ,CONTENTS_MASTER.UCM_WRITER AS UCM_WRITER ,CONTENTS_MASTER.UCM_PUBLISHER AS UCP_BRAND ,DATE_FORMAT(CONTENTS_MASTER.UCM_EBOOK_PUBDATE, '%Y/%M/%D') AS UCM_EBOOK_PUBDATE ,CONTENTS_MASTER.UCM_THUMB_URL AS UCM_COVER_url ,CONTENTS_MASTER.UCM_UCT_CODE AS UCM_UCT_CODE ,CONTENTS_MASTER.UCM_FILE_TYPE AS UCM_FILE_TYPE ,CONTENTS_MASTER.UCM_LIMIT_AGE AS UCM_LIMIT_AGE ,BOOK_REPORT.UBR_REGDATE AS UBR_REGDATE FROM TBL_BOOK_REPORT BOOK_REPORT LEFT OUTER JOIN TBL_CONTENTS_MASTER CONTENTS_MASTER ON BOOK_REPORT.UBR_UCM_CODE = CONTENTS_MASTER.UCM_CODE LEFT OUTER JOIN TBL_B2B_MEMBER_MASTER MEMBER_MASTER ON BOOK_REPORT.UBR_UM_CODE = MEMBER_MASTER.UM_CODE LEFT OUTER JOIN TBL_INSTITUTION_MASTER INSTITUTION_MASTER ON MEMBER_MASTER.UM_UIS_CODE = INSTITUTION_MASTER.UIS_CODE
JOIN TBL_RETURN_CONTENTS RETURN_CONTENTS ON CONTENTS_MASTER.UCM_CODE = RETURN_CONTENTS.URC_UCM_CODE AND RETURN_CONTENTS.URC_UCM_CODE = BOOK_REPORT.UBR_UCM_CODE
LEFT OUTER JOIN TBL_CONTENTS_EXCLUDE V ON V.UCE_UCM_CODE = CONTENTS_MASTER.UCM_CODE AND V.UCE_UIS_CODE = #{uis_code} WHERE CONTENTS_MASTER.UCM_STATUS = 'S' AND CONTENTS_MASTER.UCM_SVRYN = 'Y' AND CONTENTS_MASTER.UCM_LIMIT_AGE = 'N' AND V.UCE_UCM_CODE IS NULL
AND RETURN_CONTENTS.URC_UIS_CODE = #{uis_code}
AND BOOK_REPORT.UBR_UIS_CODE = #{uis_code}
AND ( BOOK_REPORT.UBR_IS_OPEN = 'Y' OR (BOOK_REPORT.UBR_IS_OPEN = 'N' AND BOOK_REPORT.UBR_UIS_CODE = #{uis_code}))
AND CONTENTS_MASTER.UCM_COPY_BOOK_FLAG = 'N'
AND CONTENTS_MASTER.UCM_UCP_CODE = #{uis_ucp_code}
AND REPLACE(CONTENTS_MASTER.UCM_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchKey}, '%')
GROUP BY BOOK_REPORT.UBR_UCM_CODE ORDER BY BOOK_REPORT.UBR_REGDATE DESC LIMIT #{pagenum}, #{pageSize}

SELECT COUNT(A.ubr_code) FROM( SELECT book_report.UBR_CODE AS ubr_code FROM TBL_BOOK_REPORT book_report LEFT OUTER JOIN TBL_CONTENTS_MASTER contents_master ON book_report.UBR_UCM_CODE = contents_master.UCM_CODE LEFT OUTER JOIN TBL_B2B_MEMBER_MASTER member_master ON book_report.UBR_UM_CODE = member_master.UM_CODE LEFT OUTER JOIN TBL_CP_MASTER cp_master ON contents_master.UCM_UCP_CODE = cp_master.UCP_CODE
WHERE 1 = 1 AND book_report.UBR_UCM_CODE = #{ucm_code}
AND book_report.UBR_IS_OPEN ='N' AND book_report.UBR_UIS_CODE = #{uis_code}
AND (book_report.UBR_IS_OPEN = 'Y' OR (book_report.UBR_IS_OPEN ='N' AND book_report.UBR_UIS_CODE = #{uis_code}))
) A

SELECT book_report.UBR_CODE AS ubr_code , book_report.UBR_UM_CODE AS ubr_um_code , book_report.UBR_TITLE AS ubr_title , book_report.UBR_CONTENT AS ubr_content , book_report.UBR_IS_OPEN AS ubr_is_open , book_report.UBR_REGDATE AS ubr_regdate , (SELECT COUNT(UBRC_CODE) FROM TBL_BOOK_REPORT_COMMENT WHERE UBRC_UBR_CODE = book_report.UBR_CODE AND UBRC_TYPE = 'Y') AS ubr_like , (SELECT UBRC_TYPE FROM TBL_BOOK_REPORT_COMMENT WHERE UBRC_UBR_CODE = book_report.UBR_CODE AND UBRC_UM_CODE = #{um_code}) AS ubrc_type , member_master.UM_USERID AS um_userid , contents_master.UCM_CODE AS ucm_code , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_PUBLISHER AS ucp_brand , DATE_FORMAT(contents_master.UCM_EBOOK_PUBDATE, '%Y/%m/%d') AS ucm_ebook_pubdate , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_UCT_CODE AS ucm_uct_code , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_LIMIT_AGE AS ucm_limit_age , (SELECT UBRC_CODE FROM TBL_BOOK_REPORT_COMMENT WHERE UBRC_UBR_CODE = book_report.UBR_CODE AND UBRC_UM_CODE = #{um_code}) AS ubrc_code
FROM TBL_BOOK_REPORT book_report LEFT OUTER JOIN TBL_CONTENTS_MASTER contents_master ON book_report.UBR_UCM_CODE = contents_master.UCM_CODE LEFT OUTER JOIN TBL_B2B_MEMBER_MASTER member_master ON book_report.UBR_UM_CODE = member_master.UM_CODE WHERE 1 = 1 AND book_report.UBR_UCM_CODE = #{ucm_code}
AND book_report.UBR_IS_OPEN ='N' AND book_report.UBR_UIS_CODE = #{uis_code}
AND (book_report.UBR_IS_OPEN = 'Y' OR (book_report.UBR_IS_OPEN ='N' AND book_report.UBR_UIS_CODE = #{uis_code}))
ORDER BY book_report.UBR_REGDATE DESC LIMIT #{pagenum}, #{pageSize}

SELECT COUNT(A.ucd_code) FROM( SELECT content_discussion.UCD_CODE AS ucd_code FROM TBL_CONTENT_DISCUSSION content_discussion LEFT OUTER JOIN TBL_CONTENTS_MASTER contents_master ON content_discussion.UCD_UCM_CODE = contents_master.UCM_CODE LEFT OUTER JOIN TBL_B2B_MEMBER_MASTER member_master ON content_discussion.UCD_UM_CODE = member_master.UM_CODE LEFT OUTER JOIN TBL_CP_MASTER cp_master ON contents_master.UCM_UCP_CODE = cp_master.UCP_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE AND return_contents.URC_UCM_CODE = content_discussion.UCD_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE 1=1 AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y' AND V.uce_ucm_code is null AND content_discussion.UCD_UIS_CODE = #{uis_code}
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND REPLACE(contents_master.UCM_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchKey}, '%')
GROUP BY content_discussion.UCD_UCM_CODE ) A

SELECT content_discussion.UCD_CODE AS ucd_code , contents_master.UCM_CODE AS ucm_code , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_PUBLISHER AS ucp_brand , DATE_FORMAT(contents_master.UCM_EBOOK_PUBDATE, '%Y/%m/%d') AS ucm_ebook_pubdate , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_UCT_CODE AS ucm_uct_code , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_LIMIT_AGE AS ucm_limit_age FROM TBL_CONTENT_DISCUSSION content_discussion LEFT OUTER JOIN TBL_CONTENTS_MASTER contents_master ON content_discussion.UCD_UCM_CODE = contents_master.UCM_CODE LEFT OUTER JOIN TBL_B2B_MEMBER_MASTER member_master ON content_discussion.UCD_UM_CODE = member_master.UM_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE AND return_contents.URC_UCM_CODE = content_discussion.UCD_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE 1=1 AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y' AND content_discussion.UCD_UIS_CODE = #{uis_code} AND V.uce_ucm_code is null
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND REPLACE(contents_master.UCM_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchKey}, '%')
GROUP BY content_discussion.UCD_UCM_CODE ORDER BY content_discussion.UCD_REGDATE DESC LIMIT #{pagenum}, #{pageSize}

SELECT COUNT(A.ucd_code) FROM( SELECT content_discussion.UCD_CODE AS ucd_code FROM TBL_CONTENT_DISCUSSION content_discussion LEFT OUTER JOIN TBL_CONTENT_DISCUSSION_COMMENT discussion_comment ON content_discussion.UCD_CODE = discussion_comment.UCDC_UCD_CODE AND discussion_comment.UCDC_UM_CODE = #{um_code} WHERE 1 = 1 AND content_discussion.UCD_UCM_CODE = #{ucm_code} AND content_discussion.UCD_UIS_CODE = #{uis_code}
AND content_discussion.UCD_UM_CODE = #{ucd_um_code}
) A

SELECT content_discussion.UCD_CODE AS ucd_code , content_discussion.UCD_UCM_CODE AS ucd_ucm_code , content_discussion.UCD_UIS_CODE AS ucd_uis_code , content_discussion.UCD_UM_CODE AS ucd_um_code , content_discussion.UCD_UM_USERID AS ucd_um_userid , content_discussion.UCD_COMMENT AS ucd_comment , DATE_FORMAT(content_discussion.UCD_REGDATE, '%Y.%m.%d %H:%i') AS ucd_regdate , (SELECT COUNT(UCDC_CODE) FROM TBL_CONTENT_DISCUSSION_COMMENT WHERE UCDC_UCD_CODE = content_discussion.UCD_CODE AND UCDC_UIS_CODE = #{uis_code} AND UCDC_TYPE = 'Y') AS like_count , discussion_comment.UCDC_CODE AS ucdc_code , discussion_comment.UCDC_UM_CODE AS ucdc_um_code FROM TBL_CONTENT_DISCUSSION content_discussion LEFT OUTER JOIN TBL_CONTENT_DISCUSSION_COMMENT discussion_comment ON content_discussion.UCD_CODE = discussion_comment.UCDC_UCD_CODE AND discussion_comment.UCDC_UM_CODE = #{um_code} WHERE 1 = 1 AND content_discussion.UCD_UCM_CODE = #{ucm_code} AND content_discussion.UCD_UIS_CODE = #{uis_code}
AND content_discussion.UCD_UM_CODE = #{ucd_um_code}
ORDER BY content_discussion.UCD_REGDATE DESC LIMIT #{pagenum}, #{pageSize}

